from django.http import JsonResponse
from .tasks import send_email_report

def request_report(request):
    result = send_email_report.delay(
        user_id=request.user.id,
        report_type=request.POST.get("type", "monthly"),
    )
    return JsonResponse({"task_id": result.id, "status": "queued"}, status=202)

def report_status(request, task_id):
    from celery.result import AsyncResult
    r = AsyncResult(task_id)
    data = {"task_id": task_id, "status": r.status}
    if r.status == "SUCCESS":
        data["result"] = r.result
    elif r.status == "FAILURE":
        data["error"] = str(r.result)
    return JsonResponse(data)

