import anthropic
from celery import shared_task
from celery.utils.log import get_task_logger

logger = get_task_logger(__name__)

@shared_task(
    bind=True,
    max_retries=3,
    name="ai.tasks.summarize_document",
    track_started=True,
)
def summarize_document(self, document_id: int, model: str = "claude-opus-4-5") -> dict:
    """
    Call Anthropic Claude to summarize a stored document.
    Progress is exposed via AsyncResult.info for frontend polling.
    """
    from myapp.models import Document

    self.update_state(state="STARTED", meta={"progress": 0, "step": "loading"})
    try:
        doc = Document.objects.get(pk=document_id)
        self.update_state(state="STARTED", meta={"progress": 10, "step": "calling_llm"})

        client = anthropic.Anthropic()  # reads ANTHROPIC_API_KEY from env
        message = client.messages.create(
            model=model,
            max_tokens=1024,
            messages=[{
                "role": "user",
                "content": (
                    "Summarize the following document in 3-5 concise bullet points:\n\n"
                    + doc.content[:50_000]
                ),
            }],
        )

        summary = message.content[0].text
        self.update_state(state="STARTED", meta={"progress": 80, "step": "saving"})

        doc.summary = summary
        doc.save(update_fields=["summary"])

        logger.info(
            "Summarized document %d: %d input tokens, %d output tokens",
            document_id,
            message.usage.input_tokens,
            message.usage.output_tokens,
        )
        return {
            "document_id": document_id,
            "summary": summary,
            "input_tokens": message.usage.input_tokens,
            "output_tokens": message.usage.output_tokens,
        }

    except anthropic.RateLimitError as exc:
        logger.warning("Rate limited on document %d, retrying in 60s", document_id)
        raise self.retry(exc=exc, countdown=60)

    except anthropic.APIConnectionError as exc:
        raise self.retry(exc=exc, countdown=10 * (2 ** self.request.retries))


# Status endpoint to pair with the task above
def summarize_status(request, task_id: str):
    from django.http import JsonResponse
    from celery.result import AsyncResult

    r = AsyncResult(task_id)
    if r.state == "PENDING":
        return JsonResponse({"state": "PENDING", "progress": 0})
    if r.state == "STARTED":
        meta = r.info or {}
        return JsonResponse({
            "state": "STARTED",
            "progress": meta.get("progress", 0),
            "step": meta.get("step", ""),
        })
    if r.state == "SUCCESS":
        return JsonResponse({"state": "SUCCESS", "result": r.result})
    return JsonResponse({"state": "FAILURE", "error": str(r.result)}, status=500)

