import anthropic, json, re
from celery import shared_task, chain
from myapp.models import Contract

@shared_task(bind=True, max_retries=3, name="pipeline.extract_text")
def extract_text(self, contract_id: int) -> dict:
    """OCR and text extraction from uploaded PDF. Typically 2-10 s."""
    import pdfplumber
    contract = Contract.objects.get(pk=contract_id)
    with pdfplumber.open(contract.file.path) as pdf:
        text = "\n".join(page.extract_text() or "" for page in pdf.pages)
    contract.raw_text = text
    contract.save(update_fields=["raw_text"])
    return {"contract_id": contract_id, "char_count": len(text)}

@shared_task(bind=True, max_retries=3, name="pipeline.classify_clauses")
def classify_clauses(self, upstream: dict) -> dict:
    """Classify legal clauses using Claude. Typically 8-25 s."""
    contract_id = upstream["contract_id"]
    contract = Contract.objects.get(pk=contract_id)
    client = anthropic.Anthropic()
    response = client.messages.create(
        model="claude-opus-4-5",
        max_tokens=2048,
        messages=[{
            "role": "user",
            "content": (
                "Identify all clauses in this contract. Return a JSON array where each "
                "element has: type (string), excerpt (first 100 chars), "
                "risk_level (low|medium|high).\n\n" + contract.raw_text[:40_000]
            ),
        }],
    )
    match = re.search(r"\[.*\]", response.content[0].text, re.DOTALL)
    clauses = json.loads(match.group()) if match else []
    contract.clauses = clauses
    contract.save(update_fields=["clauses"])
    return {"contract_id": contract_id, "clause_count": len(clauses)}

@shared_task(bind=True, max_retries=2, name="pipeline.score_risk")
def score_risk(self, upstream: dict) -> dict:
    """Aggregate clause risk into a 0-100 contract risk score."""
    contract_id = upstream["contract_id"]
    contract = Contract.objects.get(pk=contract_id)
    risk_map = {"low": 1, "medium": 3, "high": 10}
    total = sum(risk_map.get(c.get("risk_level", "low"), 1) for c in (contract.clauses or []))
    score = min(100, total)
    contract.risk_score = score
    contract.status = "processed"
    contract.save(update_fields=["risk_score", "status"])
    return {"contract_id": contract_id, "risk_score": score}

def process_contract(contract_id: int):
    """Kick off the full pipeline as a Celery chain."""
    return chain(
        extract_text.s(contract_id),
        classify_clauses.s(),
        score_risk.s(),
    ).apply_async()

